#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int k, A, B;
        scanf("%d %d %d", &k, &A, &B);
        if (A > B) {
            int temp = A;
            A = B;
            B = temp;
        }
        int diff = B - A;
        if (diff == 1 || diff == k - 1) {
            printf("0\n");
        } else if (diff == k / 2) {
            printf("1\n");
        } else {
            if (k % 2 == 0) {
                printf("%d\n", k - diff - 1);
            } else {
                printf("%d\n", k - diff);
            }
        }
    }
    return 0;
}

